# Definition for a binary tree node.
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def recoverTree(self, root: TreeNode) -> None:
        self.first_swapped = None
        self.second_swapped = None
        self.prev_node = None

        def inorder_traverse(node):
            if not node:
                return

            inorder_traverse(node.left)

            if self.prev_node and node.val < self.prev_node.val:
                if not self.first_swapped:
                    self.first_swapped = self.prev_node
                self.second_swapped = node

            self.prev_node = node

            inorder_traverse(node.right)

        inorder_traverse(root)

        if self.first_swapped and self.second_swapped:
            self.first_swapped.val, self.second_swapped.val = self.second_swapped.val, self.first_swapped.val
